#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int ans = 0;
        for (int i = 1; i <= N; ++i) {
            int x; scanf("%d", &x);
            if (x <= 7) ans = i; // last occurrence will stay in ans
        }
        printf("%d\n", ans);
    }
    return 0;
}

